import ccxt.async_support as ccxt  # noqa: F402

def test_rawencode():
    exchange = ccxt.Exchange({
        'id': 'sampleexchange',
    })
    dict2 = {
        'a': 1,
        'b': '+&',
        'd': 'x123',
    }
    expected2 = 'a=1&b=+&&d=x123'
    assert exchange.rawencode(dict2) == expected2, 'rawencode: expected ' + expected2 + ' but got ' + exchange.rawencode(dict2)
